const profile = $('Read Profile').all().map(i => i.json).find(r => r.chat_id) || null;
if (!profile) return [];
const chat_id = profile.chat_id;
const targetKcal = Number(profile.target_kcal) || 0;
const targetProtein = Number(profile.target_protein_g) || 0;
const interval = Number(profile.training_days_interval) || 1;
const goal = String(profile.goal || 'maintain').toLowerCase();

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const toStr = (d) => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const today = toStr(now);
const startDate = new Date(now.getTime() - 6*86400000);
const startStr = toStr(startDate);
const inRange = (d) => {
  const s = String(d || '');
  return s >= startStr && s <= today;
};

// Food
const foodRows = $('Read Food Log').all().map(i => i.json).filter(r => inRange(r.date));
const dayMap = {};
const JUNK = ['батончик','пицц','фастфуд','бургер','чипс','газировк','конфет','шоколад','мороженое','пончик','круассан','сухарик','шаурм','картош','кола','пепси'];
let junkCount = 0;
for (const r of foodRows) {
  const d = String(r.date);
  if (!dayMap[d]) dayMap[d] = { kcal: 0, protein: 0, items: 0 };
  dayMap[d].kcal    += Number(r.kcal)    || 0;
  dayMap[d].protein += Number(r.protein) || 0;
  dayMap[d].items += 1;
  const desc = String(r.description || '').toLowerCase();
  if (JUNK.some(k => desc.includes(k))) junkCount += 1;
}
const loggedDays = Object.keys(dayMap);
const avgKcal    = loggedDays.length ? Math.round(loggedDays.reduce((s,d) => s + dayMap[d].kcal,    0) / loggedDays.length) : 0;
const avgProtein = loggedDays.length ? Math.round(loggedDays.reduce((s,d) => s + dayMap[d].protein, 0) / loggedDays.length) : 0;
const proteinHitDays = loggedDays.filter(d => dayMap[d].protein >= (targetProtein - 10)).length;
const overBudgetDays = loggedDays.filter(d => dayMap[d].kcal > targetKcal + 200).length;

// Workouts
const workoutRows = $('Read Workout Log').all().map(i => i.json).filter(r => inRange(r.date));
const expectedWorkouts = Math.floor(7 / interval);
const missedWorkouts = Math.max(0, expectedWorkouts - workoutRows.length);

// Walking
const walkRows = $('Read Walking Log').all().map(i => i.json).filter(r => inRange(r.date));
const walkDays = new Set(walkRows.map(r => String(r.date))).size;
const walkMinTotal = walkRows.reduce((s, r) => s + (Number(r.duration_min) || 0), 0);

// Body params (вес)
const bodyRows = $('Read Body Params').all().map(i => i.json)
  .filter(r => inRange(r.date))
  .sort((a, b) => String(a.date).localeCompare(String(b.date)));
let weightLine = 'Вес за неделю не записывал — на чём оцениваешь прогресс?';
if (bodyRows.length >= 2) {
  const first = Number(bodyRows[0].weight);
  const last = Number(bodyRows[bodyRows.length-1].weight);
  if (first && last) {
    const diff = (last - first).toFixed(1);
    const sign = diff >= 0 ? '+' : '';
    weightLine = `Вес: ${first}кг → ${last}кг (${sign}${diff}кг за ${bodyRows.length} замеров).`;
  }
} else if (bodyRows.length === 1) {
  weightLine = `Вес записал один раз — ${bodyRows[0].weight}кг. Замеряй чаще (1 раз в 3-4 дня, утром натощак).`;
}

// === Сборка отчёта в капральском стиле ===
const lines = [];
lines.push('🗓 *Итоги недели.*');
lines.push('');
lines.push('━━━ Цифры ━━━');
lines.push(`Дни с записью еды: ${loggedDays.length} из 7${loggedDays.length < 5 ? ' — мало, ты ленишься писать' : ''}.`);
if (loggedDays.length > 0) {
  lines.push(`Среднее: ${avgKcal} ккал/день (цель ${targetKcal}).`);
  lines.push(`Средний белок: ${avgProtein}г/день (цель ${targetProtein}).`);
  lines.push(`Дни белок добран: ${proteinHitDays}/${loggedDays.length}.`);
  lines.push(`Дни с перебором ккал >200: ${overBudgetDays}.`);
}
lines.push(`Тренировки: ${workoutRows.length}/${expectedWorkouts}${missedWorkouts ? ` — пропустил ${missedWorkouts}` : ' ✅'}.`);
lines.push(`Ходьба: ${walkDays} дн, ${walkMinTotal} мин суммарно.`);
lines.push(`Мусорная еда (батончики/фастфуд/чипсы): ${junkCount} раз${junkCount >= 5 ? ' — это много' : ''}.`);
lines.push(`${weightLine}`);
lines.push('');

// === Вердикт капрала ===
lines.push('━━━ Разбор ━━━');
const verdict = [];

if (loggedDays.length < 4) verdict.push('🚨 Меньше половины дней с записями — без данных я тебе не помогу. Пиши КАЖДЫЙ день, даже если еда дрянь.');
if (missedWorkouts >= 2) verdict.push(`🏋️ Пропустил ${missedWorkouts} трен — это не отдых, это откат. На следующей неделе компенсация.`);
if (proteinHitDays < loggedDays.length / 2 && loggedDays.length >= 3) verdict.push(`🥩 Белок добран только ${proteinHitDays}/${loggedDays.length} дн. На дефиците (lose) — белок ключевой. Без него теряешь мышцы, не жир.`);
if (overBudgetDays >= 3) verdict.push(`🍕 ${overBudgetDays} дн перебор >200 ккал. Если цель похудение — на этой неделе минус как минимум 1500 ккал суммарно.`);
if (junkCount >= 5) verdict.push(`⚠️ ${junkCount} «мусорных» приёма пищи за неделю. Если хочешь результата — не «исключать», а «реже». Договорись с собой: не больше 2 в неделю.`);
if (walkMinTotal < 100 && missedWorkouts >= 2) verdict.push(`🚶 Ходьбы мало + трен пропустил — неделя малоподвижная. Замени один пропуск на 60 мин ходьбы как минимум.`);
if (bodyRows.length === 0) verdict.push('⚖️ Вес не замерял ни разу. Без замеров — гадание. Завтра утром натощак, в трусах, и записал.');

// Если всё хорошо — сухая похвала
if (!verdict.length) {
  lines.push('Неделя ровная. Цифры в норме, трены закрыты, белок добран. Не расслабляйся — следующая такая же.');
} else {
  for (const v of verdict) lines.push(`- ${v}`);
}

// Домашка
lines.push('');
lines.push('━━━ На следующую неделю ━━━');
const homework = [];
if (proteinHitDays < loggedDays.length * 0.7) homework.push('Белок добивать каждый день. Минимум 4 источника: утро яйца/творог, обед мясо/рыба, ужин курица/рыба, перед сном творог или казеин.');
if (junkCount >= 3) homework.push('Сокращай мусор. Замени 2 приёма пищи на нормальные альтернативы (см. форекаст-советы).');
if (missedWorkouts >= 1) homework.push('Закрыть все плановые тренировки. Не пропускать.');
if (bodyRows.length < 2) homework.push('Записывать вес 2-3 раза в неделю утром натощак.');
if (!homework.length) homework.push('Держать заданный темп. Не падать.');
for (const h of homework) lines.push(`- ${h}`);

const text = lines.join('\n');
return [{ json: { chat_id, text } }];
